previewCss:
.darma-loader-darma-custom-272 {
  color: var(--loader-color, #16a34a);
  display: inline-grid;
  padding: 5px;
  background: var(--loader-bg, #ffffff);
  border-radius: 999px;
  filter: blur(4px) contrast(12);
}
.darma-loader-darma-custom-272:before,
.darma-loader-darma-custom-272:after {
  content: "";
  grid-area: 1/1;
  height: 40px;
  aspect-ratio: 3;
  --c: #0000 64%,currentColor 66% 98%,#0000 101%;
  background:
    radial-gradient(35% 146% at 50% 159%,var(--c)) 0 0,
    radial-gradient(35% 146% at 50% -59%,var(--c)) 100% 100%;
  background-size: calc(200%/3) 50%;
  background-repeat: repeat-x;
}
.darma-loader-darma-custom-272:before {
  -webkit-mask: repeating-linear-gradient(90deg,currentColor 0 8%,#0000 0 15%);
}
.darma-loader-darma-custom-272:after {
  clip-path: inset(0 100% 0 0);
  animation: darma-loader-darma-custom-272-l13 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-272-l13{
  50% {clip-path: inset(0)}
  to {clip-path: inset(0 0 0 100%)}
}

